SELECT sys04_role.*, f_get_company_nm(sys04_company_id) AS sys04_company_nm
  FROM sys04_role
 WHERE sys04_role_id = #{roleId}

SELECT sys04_role.*, f_get_company_nm(sys04_company_id) AS sys04_company_nm
  FROM sys04_role
 WHERE sys04_role_nm LIKE #{roleName}
   AND sys04_company_id = #{companyId}
 ORDER BY sys04_seq
